DELETE FROM posts WHERE id IN ('civicavita-editorial-evidence','civicavita-editorial-ai','civicavita-editorial-systems');
INSERT OR REPLACE INTO posts (id,title,excerpt,content,category,author,author_role,date,cover_emoji,cover_image,read_minutes,tags,locale,translation_key) VALUES
('editorial-evidence-field','From field experience to public evidence: a careful starting point','CIVICAVITA begins its public work by separating documented professional experience from claims about a new organisation.','CIVICAVITA AB is developing its public research and advisory work from Sweden. Its starting point is not a claim to have already delivered large-scale programmes. It is a commitment to use evidence carefully, state scope clearly and build work progressively.\n\nDr. Sahar Motallebi brings documented professional experience in public health and humanitarian contexts, including roles with ministries, WHO, UNICEF, UNDP and UN Women. Those experiences inform the perspective of the practice; they do not make those institutions current CIVICAVITA partners.\n\nThis distinction matters. In global health, credibility depends on transparent attribution, appropriate evidence and respect for the people and institutions closest to the issue.','Editorial','CIVICAVITA AB','Editorial team','2026-07-21','🔎','/images/insight-evidence-health.jpg',2,'["Evidence","Transparency","Global Health"]','en','evidence-field'),
('editorial-displacement-health','Displacement, shelter and health: questions that need long-term attention','Reflections informed by documented work on social determinants of health in displaced populations and post-disaster sheltering.','Temporary shelter is never only a logistical question. It affects privacy, safety, exposure to weather, continuity of care and the social conditions that shape health.\n\nDr. Motallebi''s documented academic and professional record includes work on social determinants of health for displaced populations and a 2006 conference publication on semi-permanent sheltering after disasters. These experiences point to an enduring question for researchers and decision-makers: what happens when a short-term response becomes a long-term living condition?\n\nCIVICAVITA will explore this topic through careful research synthesis and public-facing notes, without presenting past work as a current programme.','Humanitarian Science','CIVICAVITA AB','Editorial team','2026-07-18','⛺','/images/insight-humanitarian-research.jpg',2,'["Displacement","Shelter","Health Equity"]','en','displacement-health'),
('editorial-health-systems','Resilient health systems are built through continuity, learning and trust','Health systems resilience is not a technology claim; it is sustained work on institutions, data, people and access to care.','Health systems experience pressure from many directions: chronic disease, climate risks, displacement, workforce shortages and unequal access to information. Resilience is not a product that can be installed. It is a capacity developed through continuity of care, local knowledge, learning and accountable institutions.\n\nThe founder''s record includes technical work relating to non-communicable disease policy, monitoring and evaluation, disaster planning and health programming. CIVICAVITA draws on those documented areas of experience to frame questions for research and advisory work.\n\nOur public writing will focus on useful questions, clear evidence and practical limits rather than promises of transformation.','Health Systems','CIVICAVITA AB','Editorial team','2026-07-15','🏥','/images/insight-health-systems.jpg',2,'["Health Systems","Resilience","Policy"]','en','health-systems'),
('editorial-responsible-ai','Responsible AI starts with accountable human judgment','AI may assist research and communication, but it cannot replace contextual knowledge, ethical review or responsibility.','AI can help organise information, create structured first drafts and support knowledge workflows. In public health and humanitarian settings, however, a fluent answer is not necessarily a reliable one.\n\nCIVICAVITA treats AI as assistive technology. Sources need checking, uncertainty needs stating and people with relevant contextual knowledge remain responsible for decisions. This approach is especially important when data are incomplete, situations change quickly or the consequences of an error are serious.\n\nAs a recently active public practice, CIVICAVITA is exploring responsible AI methods carefully and will publish only work that has appropriate human review.','Responsible AI','CIVICAVITA AB','Editorial team','2026-07-12','🧠','/images/insight-responsible-ai.jpg',2,'["Responsible AI","Ethics","Research"]','en','responsible-ai');
